// // This SRAM cell stores data only when WE is low
module sram_cell (
    input wire D,
    input wire WE,
    output reg Q
);
    always @(WE or D) begin
        if (WE) begin
            Q <= D; // Store data when WE is high
        end
        // If WE is low, maintain the previous value of Q
    end
endmodule
